x = 21/5;
y = 45/7;

A = 12*dir(60);
Ap = (9,0);
B = (0,0);
C = (12,0);
P = x*dir(60);
Q = C + y*dir(120);

draw(B--C--Q--P--cycle);
draw(P--Ap--Q);
draw(P--A--Q,dashed);

