O = (0,0);
A = dir(90);
B = dir(-30);
C = dir(210);
D = extension(B, B + rotate(90)*(B), C, C + rotate(90)*(C));

draw(Circle(O,1));
draw(A--B--C--cycle);
draw(B--D--C);

label("$A$", A, N);
label("$B$", B, SE);
label("$C$", C, SW);
label("$D$", D, S);
